    57→        job_description,
    58→        5
    59→      );
    60→      console.log('AI generated', questions.length, 'interview questions');
    61→    } catch (aiErr) {
    62→      console.error('AI question generation failed, using fallback questions:', aiErr.message);
    63→      questions = FALLBACK_QUESTIONS;
    64→    }
    65→
    66→    // Validate questions array
    67→    if (!questions || !Array.isArray(questions) || questions.length === 0) {
