   550→    // Default question text from library if not provided
   551→    const libraryQ = PRACTICE_QUESTION_LIBRARY.find(q => q.id === question_id);
   552→    const question = req.body.question || (libraryQ && libraryQ.question) || `Practice question ${question_id || 'unknown'}`;
   553→
   554→    if (!response_text || response_text.trim().length < 50) {
   555→      return res.status(400).json({ error: 'Response must be at least 50 characters' });
   556→    }
   557→
   558→    // Look up key_points from question library
   559→    const libraryQuestion = PRACTICE_QUESTION_LIBRARY.find(q => q.id === question_id);
   560→    const keyPoints = libraryQuestion ? libraryQuestion.key_points : ['Content quality', 'Structure', 'Clarity', 'Relevance'];
