   562→    // First, analyze the response with real key points
   563→    const analysis = await analyzeInterviewResponse(
   564→      question,
   565→      response_text,
   566→      keyPoints,
   567→      { subscriptionId: req.user.stripe_subscription_id }
   568→    );
   569→
   570→    // Then, generate detailed coaching
   571→    const coaching = await generateInterviewCoaching(
   572→      question,
