   574→// Select evenly-spaced key frames from a larger set
   575→function selectKeyFrames(frames, count) {
   576→  const result = [];
   577→  const step = (frames.length - 1) / (count - 1);
   578→  for (let i = 0; i < count; i++) {
   579→    result.push(frames[Math.round(i * step)]);
   580→  }
   581→  return result;
   582→}
