   584→// Analyze speech transcription for communication quality
   585→function analyzeSpeechPatterns(transcription, durationSeconds) {
   586→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   587→  const wordCount = words.length;
   588→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   589→
   590→  // Filler word detection
   591→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   592→  const fillerCounts = {};
   593→  let totalFillers = 0;
   594→  const lowerTranscription = transcription.toLowerCase();
   595→
   596→  for (const filler of fillerWords) {
   597→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   598→    const matches = lowerTranscription.match(regex);
   599→    if (matches && matches.length > 0) {
   600→      fillerCounts[filler] = matches.length;
   601→      totalFillers += matches.length;
   602→    }
   603→  }
   604→
   605→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   606→
   607→  // Pace analysis
   608→  let paceAssessment = 'good';
   609→  let paceFeedback = '';
   610→  if (wpm < 100) {
   611→    paceAssessment = 'too_slow';
   612→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   613→  } else if (wpm < 120) {
   614→    paceAssessment = 'slightly_slow';
   615→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   616→  } else if (wpm <= 160) {
   617→    paceAssessment = 'good';
   618→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   619→  } else if (wpm <= 180) {
   620→    paceAssessment = 'slightly_fast';
   621→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   622→  } else {
   623→    paceAssessment = 'too_fast';
   624→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   625→  }
   626→
   627→  // Sentence structure analysis
   628→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   629→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   630→
   631→  // Communication score (1-10)
   632→  let communicationScore = 7;
   633→  // Penalize for filler words
   634→  if (fillerRate > 5) communicationScore -= 2;
   635→  else if (fillerRate > 3) communicationScore -= 1;
   636→  // Penalize for bad pace
   637→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   638→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   639→  // Reward for good sentence structure
   640→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   641→  // Penalize for very short responses
   642→  if (wordCount < 50) communicationScore -= 2;
   643→  else if (wordCount < 100) communicationScore -= 1;
   644→  // Reward for substantial responses
   645→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   646→
   647→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   648→
   649→  return {
   650→    word_count: wordCount,
   651→    duration_seconds: durationSeconds,
   652→    words_per_minute: wpm,
   653→    filler_words: fillerCounts,
   654→    total_fillers: totalFillers,
   655→    filler_rate: Math.round(fillerRate * 10) / 10,
   656→    pace: {
   657→      assessment: paceAssessment,
   658→      wpm,
   659→      feedback: paceFeedback
   660→    },
   661→    sentence_count: sentences.length,
   662→    avg_sentence_length: avgSentenceLength,
   663→    communication_score: communicationScore,
   664→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   665→  };
   666→}
   667→
   668→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   669→  const tips = [];
   670→
   671→  if (fillerRate > 3) {
   672→    const topFillers = Object.entries(fillerCounts)
   673→      .sort((a, b) => b[1] - a[1])
   674→      .slice(0, 3)
   675→      .map(([word, count]) => `"${word}" (${count}x)`);
   676→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   677→  }
   678→
   679→  if (wpm > 160) {
   680→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   681→  } else if (wpm < 110) {
   682→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   683→  }
   684→
   685→  if (wordCount < 80) {
   686→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   687→  }
   688→
   689→  if (tips.length === 0) {
   690→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   691→  }
   692→
   693→  return tips;
   694→}
