   696→// Comprehensive video interview analysis combining all signals
   697→async function analyzeVideoInterviewResponse(question, transcription, frames, durationSeconds, keyPoints, options = {}) {
   698→  // Run analyses in parallel
   699→  const [contentAnalysis, contentCoaching, videoAnalysis] = await Promise.all([
   700→    analyzeInterviewResponse(question, transcription, keyPoints, options),
   701→    generateInterviewCoaching(question, transcription, { score: 5, strengths: [], improvements: [] }, options),
   702→    analyzeVideoPresentation(frames, options)
   703→  ]);
   704→
   705→  // Algorithmic speech analysis (no AI needed)
   706→  const speechAnalysis = analyzeSpeechPatterns(transcription, durationSeconds);
   707→
   708→  // Calculate category scores
   709→  const contentScore = contentAnalysis.score || 5;
   710→  const communicationScore = speechAnalysis.communication_score || 5;
   711→  const presentationScore = videoAnalysis.overall_presentation || 5;
   712→
   713→  // Weighted overall score
   714→  const overallScore = Math.round(
   715→    (contentScore * 0.45 + communicationScore * 0.25 + presentationScore * 0.30) * 10
   716→  ) / 10;
   717→
